#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 50
#define MAXM 50

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        char grid[MAXN][MAXM + 1];
        for (int i = 0; i < N; i++) {
            scanf("%s", grid[i]);
        }
        // Find positions of lasers and enemies
        int laserCount = 0;
        int enemyCount = 0;
        int lasers[MAXN * MAXM][2];
        int enemies[MAXN * MAXM][2];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (grid[i][j] == 'L') {
                    lasers[laserCount][0] = i;
                    lasers[laserCount][1] = j;
                    laserCount++;
                } else if (grid[i][j] == 'E') {
                    enemies[enemyCount][0] = i;
                    enemies[enemyCount][1] = j;
                    enemyCount++;
                }
            }
        }
        // Perform BFS traversal for each laser
        int visited[MAXN * MAXM];
        for (int i = 0; i < laserCount; i++) {
            int queue[MAXN * MAXM][2];
            int front = 0;
            int rear = 0;
            queue[rear][0] = lasers[i][0];
            queue[rear][1] = lasers[i][1];
            rear++;
            while (front < rear) {
                int x = queue[front][0];
                int y = queue[front][1];
                front++;
                // Check left direction
                for (int j = y - 1; j >= 0; j--) {
                    if (grid[x][j] == 'E') {
                        visited[enemyCount--] = 1;
                    } else if (grid[x][j] == 'L') {
                        break;
                    }
                }
                // Check right direction
                for (int j = y + 1; j < M; j++) {
                    if (grid[x][j] == 'E') {
                        visited[enemyCount--] = 1;
                    } else if (grid[x][j] == 'L') {
                        break;
                    }
                }
                // Check up direction
                for (int j = x - 1; j >= 0; j--) {
                    if (grid[j][y] == 'E') {
                        visited[enemyCount--] = 1;
                    } else if (grid[j][y] == 'L') {
                        break;
                    }
                }
            }
        }
        if (enemyCount == 0) {
            printf("Possible\n");
        } else {
            printf("Impossible\n");
        }
    }
    return 0;
}

