        for j in range(M):
            if grid[i][j] == 'L':
                lasers.append((i, j))
                laser_count += 1
            elif grid[i][j] == 'E':
                enemies.append((i, j))
                enemy_count += 1
    # Perform BFS traversal for each laser
    visited = [False] * enemy_count
    for i in range(laser_count):
        q = deque([lasers[i]])
        while q:
            x, y = q.popleft()
            # Check left direction
            for j in range(y - 1, -1, -1):
                if grid[x][j] == 'E':
                    visited[enemy_count - 1] = True
                    enemy_count -= 1
                elif grid[x][j] == 'L':
                    break
